PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" varchar not null, "queue" varchar not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "role_id" integer, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "avatar" varchar, "bio" text, "is_active" tinyint(1) not null default '1', "remember_token" varchar, "created_at" datetime, "updated_at" datetime, foreign key("role_id") references "roles"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "layouts" ("id" integer primary key autoincrement not null, "theme_id" integer not null, "name" varchar not null, "slug" varchar not null, "view_path" varchar not null, "description" text, "is_default" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("theme_id") references "themes"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "components" ("id" integer primary key autoincrement not null, "theme_id" integer not null, "name" varchar not null, "slug" varchar not null, "type" varchar check ("type" in ('header', 'footer', 'sidebar', 'hero', 'pricing', 'testimonial', 'section', 'widget', 'cta', 'custom')) not null default 'section', "variant" varchar not null default 'variant1', "view_path" varchar, "thumbnail" varchar, "content" text, "settings" text, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("theme_id") references "themes"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "tags" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "post_tag" ("post_id" integer not null, "tag_id" integer not null, foreign key("post_id") references "posts"("id") on delete cascade, foreign key("tag_id") references "tags"("id") on delete cascade, primary key ("post_id", "tag_id"));
CREATE TABLE IF NOT EXISTS "page_components" ("id" integer primary key autoincrement not null, "page_id" integer not null, "component_id" integer not null, "region" varchar not null default 'content', "order" integer not null default '0', "settings_override" text, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("page_id") references "pages"("id") on delete cascade, foreign key("component_id") references "components"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "media" ("id" integer primary key autoincrement not null, "user_id" integer, "file_name" varchar not null, "file_path" varchar not null, "mime_type" varchar, "size" integer, "alt_text" varchar, "caption" varchar, "collection" varchar not null default 'default', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "menus" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "location" varchar not null default 'header', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "menu_items" ("id" integer primary key autoincrement not null, "menu_id" integer not null, "parent_id" integer, "page_id" integer, "post_id" integer, "title" varchar not null, "url" varchar, "icon" varchar, "target" varchar not null default '_self', "order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("menu_id") references "menus"("id") on delete cascade, foreign key("parent_id") references "menu_items"("id") on delete set null, foreign key("page_id") references "pages"("id") on delete set null, foreign key("post_id") references "posts"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "seo_metas" ("id" integer primary key autoincrement not null, "seo_metable_type" varchar not null, "seo_metable_id" integer not null, "meta_title" varchar, "meta_description" varchar, "meta_keywords" varchar, "focus_keyword" varchar, "canonical_url" varchar, "locale" varchar not null default 'id', "hreflang_group" varchar, "robots_index" tinyint(1) not null default '1', "robots_follow" tinyint(1) not null default '1', "og_title" varchar, "og_description" varchar, "og_image" varchar, "og_type" varchar not null default 'website', "twitter_card" varchar not null default 'summary_large_image', "twitter_title" varchar, "twitter_description" varchar, "twitter_image" varchar, "schema_markup" text, "sitemap_include" tinyint(1) not null default '1', "sitemap_priority" numeric not null default '0.5', "sitemap_change_freq" varchar not null default 'weekly', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "redirects" ("id" integer primary key autoincrement not null, "old_url" varchar not null, "new_url" varchar not null, "type" integer not null default '301', "hits" integer not null default '0', "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "comments" ("id" integer primary key autoincrement not null, "post_id" integer not null, "user_id" integer, "parent_id" integer, "author_name" varchar, "author_email" varchar, "content" text not null, "status" varchar check ("status" in ('pending', 'approved', 'spam', 'rejected')) not null default 'pending', "created_at" datetime, "updated_at" datetime, foreign key("post_id") references "posts"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete set null, foreign key("parent_id") references "comments"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "settings" ("id" integer primary key autoincrement not null, "key" varchar not null, "value" text, "type" varchar not null default 'text', "group" varchar not null default 'general', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "translations" ("id" integer primary key autoincrement not null, "translatable_type" varchar not null, "translatable_id" integer not null, "locale" varchar not null, "field" varchar not null, "value" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "revisions" ("id" integer primary key autoincrement not null, "revisionable_type" varchar not null, "revisionable_id" integer not null, "user_id" integer, "data" text not null, "note" varchar, "created_at" datetime not null default CURRENT_TIMESTAMP, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "activity_logs" ("id" integer primary key autoincrement not null, "user_id" integer, "action" varchar not null, "subject_type" varchar, "subject_id" integer, "properties" text, "ip_address" varchar, "user_agent" varchar, "created_at" datetime not null default CURRENT_TIMESTAMP, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "search_logs" ("id" integer primary key autoincrement not null, "query" varchar not null, "results_count" integer not null default '0', "user_id" integer, "session_id" varchar, "created_at" datetime not null default CURRENT_TIMESTAMP, foreign key("user_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "post_views" ("id" integer primary key autoincrement not null, "post_id" integer not null, "viewed_date" date not null, "views_count" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("post_id") references "posts"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "post_related" ("post_id" integer not null, "related_post_id" integer not null, "order" integer not null default '0', foreign key("post_id") references "posts"("id") on delete cascade, foreign key("related_post_id") references "posts"("id") on delete cascade, primary key ("post_id", "related_post_id"));
CREATE TABLE IF NOT EXISTS "approvals" ("id" integer primary key autoincrement not null, "approvable_type" varchar not null, "approvable_id" integer not null, "submitted_by" integer not null, "reviewed_by" integer, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "notes" text, "reviewed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("submitted_by") references "users"("id") on delete cascade, foreign key("reviewed_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "forms" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "success_message" text, "notification_email" varchar, "settings" text, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "form_fields" ("id" integer primary key autoincrement not null, "form_id" integer not null, "label" varchar not null, "name" varchar not null, "type" varchar check ("type" in ('text', 'email', 'textarea', 'select', 'checkbox', 'radio', 'number', 'date', 'file')) not null default 'text', "options" text, "placeholder" varchar, "is_required" tinyint(1) not null default '0', "order" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("form_id") references "forms"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "form_submissions" ("id" integer primary key autoincrement not null, "form_id" integer not null, "data" text not null, "ip_address" varchar, "user_agent" varchar, "is_read" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("form_id") references "forms"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "notifications" ("id" varchar not null, "type" varchar not null, "notifiable_type" varchar not null, "notifiable_id" integer not null, "data" text not null, "read_at" datetime, "created_at" datetime, "updated_at" datetime, primary key ("id"));
CREATE TABLE IF NOT EXISTS "sitemap_static_entries" ("id" integer primary key autoincrement not null, "url" varchar not null, "priority" numeric not null default '0.5', "change_freq" varchar not null default 'monthly', "last_modified" datetime, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "posts" ("id" integer primary key autoincrement not null, "user_id" integer not null, "category_id" integer, "title" varchar not null, "slug" varchar not null, "excerpt" text, "content" text not null, "status" varchar not null default ('draft'), "published_at" datetime, "expired_at" datetime, "is_featured" tinyint(1) not null default ('0'), "views" integer not null default ('0'), "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "featured_image_id" integer, foreign key("category_id") references categories("id") on delete set null on update no action, foreign key("user_id") references users("id") on delete cascade on update no action, foreign key("featured_image_id") references "media"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "pages" ("id" integer primary key autoincrement not null, "user_id" integer not null, "layout_id" integer, "title" varchar not null, "slug" varchar not null, "content" text, "status" varchar not null default ('draft'), "published_at" datetime, "expired_at" datetime, "is_homepage" tinyint(1) not null default ('0'), "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "featured_image_id" integer, foreign key("layout_id") references layouts("id") on delete set null on update no action, foreign key("user_id") references users("id") on delete cascade on update no action, foreign key("featured_image_id") references "media"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "testimonials" ("id" integer primary key autoincrement not null, "name" varchar not null, "role" varchar, "company" varchar, "content" text not null, "rating" integer not null default ('5'), "is_active" tinyint(1) not null default ('1'), "created_at" datetime, "updated_at" datetime, "avatar_id" integer, foreign key("avatar_id") references "media"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "pricings" ("id" integer primary key autoincrement not null, "name" varchar not null, "price" varchar not null, "billing_period" varchar, "description" text, "features" text, "button_text" varchar not null default ('Get Started'), "button_url" varchar not null default ('#'), "is_featured" tinyint(1) not null default ('0'), "is_active" tinyint(1) not null default ('1'), "order" integer not null default ('0'), "created_at" datetime, "updated_at" datetime, "icon" varchar, "image_id" integer, foreign key("image_id") references "media"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "categories" ("id" integer primary key autoincrement not null, "parent_id" integer, "name" varchar not null, "slug" varchar not null, "description" text, "order" integer not null default ('0'), "is_active" tinyint(1) not null default ('1'), "created_at" datetime, "updated_at" datetime, "image_id" integer, foreign key("parent_id") references categories("id") on delete set null on update no action, foreign key("image_id") references "media"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "themes" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" text, "version" varchar not null default ('1.0.0'), "author" varchar, "is_active" tinyint(1) not null default ('0'), "created_at" datetime, "updated_at" datetime, "screenshot_id" integer, foreign key("screenshot_id") references "media"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
PRAGMA writable_schema=ON;
CREATE TABLE IF NOT EXISTS sqlite_sequence(name,seq);
DELETE FROM sqlite_sequence;
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE UNIQUE INDEX "roles_slug_unique" on "roles" ("slug");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE INDEX "failed_jobs_connection_queue_failed_at_index" on "failed_jobs" ("connection", "queue", "failed_at");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE UNIQUE INDEX "layouts_slug_unique" on "layouts" ("slug");
CREATE UNIQUE INDEX "components_theme_id_type_variant_unique" on "components" ("theme_id", "type", "variant");
CREATE UNIQUE INDEX "components_slug_unique" on "components" ("slug");
CREATE UNIQUE INDEX "tags_slug_unique" on "tags" ("slug");
CREATE UNIQUE INDEX "menus_slug_unique" on "menus" ("slug");
CREATE INDEX "seo_metas_seo_metable_type_seo_metable_id_index" on "seo_metas" ("seo_metable_type", "seo_metable_id");
CREATE UNIQUE INDEX "redirects_old_url_unique" on "redirects" ("old_url");
CREATE UNIQUE INDEX "settings_key_unique" on "settings" ("key");
CREATE INDEX "translations_translatable_type_translatable_id_index" on "translations" ("translatable_type", "translatable_id");
CREATE UNIQUE INDEX "translations_unique" on "translations" ("translatable_type", "translatable_id", "locale", "field");
CREATE INDEX "revisions_revisionable_type_revisionable_id_index" on "revisions" ("revisionable_type", "revisionable_id");
CREATE INDEX "activity_logs_subject_type_subject_id_index" on "activity_logs" ("subject_type", "subject_id");
CREATE INDEX "search_logs_query_index" on "search_logs" ("query");
CREATE UNIQUE INDEX "post_views_post_id_viewed_date_unique" on "post_views" ("post_id", "viewed_date");
CREATE INDEX "approvals_approvable_type_approvable_id_index" on "approvals" ("approvable_type", "approvable_id");
CREATE UNIQUE INDEX "forms_slug_unique" on "forms" ("slug");
CREATE INDEX "notifications_notifiable_type_notifiable_id_index" on "notifications" ("notifiable_type", "notifiable_id");
CREATE UNIQUE INDEX "sitemap_static_entries_url_unique" on "sitemap_static_entries" ("url");
CREATE UNIQUE INDEX "posts_slug_unique" on "posts" ("slug");
CREATE UNIQUE INDEX "pages_slug_unique" on "pages" ("slug");
CREATE UNIQUE INDEX "categories_slug_unique" on "categories" ("slug");
CREATE UNIQUE INDEX "themes_slug_unique" on "themes" ("slug");
CREATE INDEX "personal_access_tokens_tokenable_type_tokenable_id_index" on "personal_access_tokens" ("tokenable_type", "tokenable_id");
CREATE UNIQUE INDEX "personal_access_tokens_token_unique" on "personal_access_tokens" ("token");
CREATE INDEX "personal_access_tokens_expires_at_index" on "personal_access_tokens" ("expires_at");
PRAGMA writable_schema=OFF;
COMMIT;
